# Install structured log viewer CLI tool
dotnet tool install -g dotnet-msbuild-log 2>&1 || dotnet tool install -g StructuredLogViewer.Avalonia 2>&1 || true
# Try the MSBuild binary log reader NuGet approach - write a script
cat << 'EOF' > /tmp/analyze_binlog.csproj
<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net8.0</TargetFramework>
  </PropertyGroup>
  <ItemGroup>
    <PackageReference Include="MSBuild.StructuredLogger" Version="2.2.405" />
  </ItemGroup>
</Project>
EOF

cat << 'EOF' > /tmp/analyze_binlog.cs
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Collections.Generic;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD RESULT ===");
Console.WriteLine($"Succeeded: {build.Succeeded}");
Console.WriteLine();

// Collect all errors
var errors = build.FindChildrenRecursive<Error>().ToList();
Console.WriteLine($"=== ALL ERRORS ({errors.Count}) ===");
foreach (var e in errors)
{
    var project = GetParentProject(e);
    Console.WriteLine($"[{project}] {e.File}({e.LineNumber},{e.ColumnNumber}): error {e.Code}: {e.Text}");
}

Console.WriteLine();

// Collect all warnings
var warnings = build.FindChildrenRecursive<Warning>().ToList();
Console.WriteLine($"=== WARNINGS ({warnings.Count}) ===");
foreach (var w in warnings)
{
    var project = GetParentProject(w);
    Console.WriteLine($"[{project}] {w.Code}: {w.Text}");
}

Console.WriteLine();

// Show project structure
Console.WriteLine("=== PROJECT STRUCTURE ===");
var projects = build.FindChildrenRecursive<Project>().ToList();
foreach (var p in projects)
{
    var projectErrors = p.FindChildrenRecursive<Error>().ToList();
    Console.WriteLine($"Project: {System.IO.Path.GetFileName(p.ProjectFile)} | Succeeded: {p.Succeeded} | Errors: {projectErrors.Count}");
}

static string GetParentProject(BaseNode node)
{
    var current = node.Parent;
    while (current != null)
    {
        if (current is Project p) return System.IO.Path.GetFileName(p.ProjectFile);
        current = current.Parent;
    }
    return "unknown";
}
EOF

