# Let's get more details - check if Api.csproj had dependency failures and look at project references
cat << 'EOF' > /tmp/binlog_analyzer/Program.cs
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD RESULT: " + (build.Succeeded ? "SUCCESS" : "FAILED") + " ===\n");

// Get all errors
var errors = build.FindChildrenRecursive<Error>().ToList();
Console.WriteLine($"=== ERRORS ({errors.Count}) ===");
foreach (var e in errors)
{
    Console.WriteLine($"  File: {e.File}");
    Console.WriteLine($"  Location: ({e.LineNumber},{e.ColumnNumber})");
    Console.WriteLine($"  Code: {e.Code}");
    Console.WriteLine($"  Message: {e.Text}");
    Console.WriteLine();
}

// Look for project references / dependency info in messages
Console.WriteLine("=== LOOKING FOR PACKAGE REFERENCES ===");
var messages = build.FindChildrenRecursive<Message>().ToList();
foreach (var m in messages.Where(m => m.Text != null && m.Text.Contains("PackageReference") && m.Text.Contains("Newtonsoft")))
{
    Console.WriteLine($"  {m.Text}");
}
Console.WriteLine();

// Look for restore-related messages about Services project
Console.WriteLine("=== RESTORE INFO ===");
foreach (var m in messages.Where(m => m.Text != null && (m.Text.Contains("Services.csproj") || m.Text.Contains("Newtonsoft")) && m.Text.Length < 300))
{
    Console.WriteLine($"  {m.Text}");
}

// Check items for package references
Console.WriteLine("\n=== PROJECT ITEMS (PackageReference) ===");
var items = build.FindChildrenRecursive<Item>().ToList();
foreach (var item in items.Where(i => i.Text != null && i.Text.Contains("Newtonsoft")))
{
    Console.WriteLine($"  {GetParentProject(item)}: {item.Text}");
}

// Also look at AddItem
var addItems = build.FindChildrenRecursive<AddItem>().ToList();
foreach (var ai in addItems.Where(a => a.Name != null && a.Name.Contains("PackageReference")))
{
    var children = ai.Children.OfType<Item>().ToList();
    foreach (var c in children)
    {
        var proj = GetParentProject(ai);
        Console.WriteLine($"  [{proj}] PackageReference: {c.Text}");
    }
}

static string GetParentProject(BaseNode node)
{
    var current = node.Parent;
    while (current != null)
    {
        if (current is Project p) return System.IO.Path.GetFileName(p.ProjectFile);
        current = current.Parent;
    }
    return "unknown";
}
EOF

